SELECT station_id 
FROM measurements 
WHERE ksed_oxy = (SELECT MAX(ksed_oxy) FROM measurements);

SELECT type_name, description
FROM measurement_types
WHERE type_id = 0;

SELECT ms.station_name, ms.contact_email, u.user_name, u.email
FROM monitoring_stations ms
CROSS JOIN users u;

SELECT measurement_id, station_id, measurement_date, ksed_oxy, fsed_oxy 
FROM measurements 
WHERE measurement_id > 1;

SELECT station_id, station_name
FROM monitoring_stations
WHERE station_status = 'inactive';
